 51→const App = () => {
 52→
 53→  const theme = {
 54→    paragraph: 'editor-paragraph',
 55→    heading: {
 56→      h1: 'editor-heading-h1',
 57→      h2: 'editor-heading-h2',
 58→      h3: 'editor-heading-h3',
 59→    },
 60→    quote: 'editor-quote',
 61→    text: {
 62→      bold: 'editor-text-bold',
 63→      italic: 'editor-text-italic',
 64→      underline: 'editor-text-underline',
 65→    }
 66→  }
 67→  
 68→  const initaConfig = {
 69→  namespace: "MyLexicalEditor",
 70→  theme,
 71→  //register nodes
 72→  nodes: [ImageNode, HeadingNode, QuoteNode],
 73→  onError(error){
 74→  throw error;
 75→  },
 76→}
 77→
 78→  return (
 79→    <>
 80→    <LexicalComposer initialConfig={initaConfig}>
 81→      <BrowserRouter>
 82→        <SeoManager />
 83→        <AppSplash />
 84→        <Suspense fallback={null}>
 85→          <AppAuthModal/>
