 97→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
 98→              <Route path='visitedCollections' element={<CollectionViewer/>}/>
 99→              <Route path='visitedOpinions' element={<VisitedProfileOpinions/>}/>
100→            </Route>
101→
102→            <Route path='/u/:username' element={<Visitprofile/>}>
103→              <Route index element={<VisitedProfilePostCards/>}/>
104→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
105→              <Route path='collections' element={<CollectionViewer/>}/>
106→              <Route path='opinions' element={<VisitedProfileOpinions/>}/>
107→            </Route>
108→
109→            <Route path='/home' element={<HomePage/>}>
110→              <Route index element={<PostCards/>}/>
111→              <Route path='explore' element={<ExplorePage/>}/>
112→              <Route path='gallery' element={<GalleryPage/>}/>
113→              <Route path='freedom-wall' element={<FreedomWallPage/>}/>
114→              <Route path='contentViewer' element={<ContentView/>}/>
115→              <Route path='post/:journalId' element={<ContentView/>}/>
116→              <Route path='post/:journalId/:slug' element={<ContentView/>}/>
117→              <Route path='bookmark' element={<Bookmarks/>}/>
118→              <Route path='userCollections' element={<ViewUserCollection/>}/>
119→              <Route path='opinions'element={<OpinionsPage/>}/>
120→              <Route path='opinionsViewer' element={<OpinionViewer/>}/>
121→
122→              <Route path='collections' element={<Collections/>}/>
123→              <Route path='collectionCards' element={<CollectionJournals/>}/>
124→              <Route path='settings' element={<SettingsPage/>}/>
125→
126→              {/* route for nested notifications */}
127→              <Route path='notifications' element={<Notifications/>}>
128→                <Route index element={<NotificationCards/>}/>
129→                <Route path='unreadNotification' element={<UnreadNotification/>}/>
130→              </Route>  
131→            </Route>   
132→
133→            <Route path='/universe' element={<Universe/>}/>
134→
135→            <Route path='/login' element={<LoginPage/>}/>
136→            <Route path='/signUp' element={<SignUp/>}/>
137→          </Routes>
138→        </Suspense>
139→      </BrowserRouter>
140→    </LexicalComposer>
141→    </>
142→  )
143→}
144→
145→export default App
