 274→        throw new Error('limit should be an integer between 1 and 72');
 275→    }
 276→
 277→    const normalizedSort = typeof sort === 'string' && sort.trim().toLowerCase() === 'newest'
 278→        ? 'newest'
 279→        : 'hottest';
