 30→const normalizeInteractionFlag = (value) => {
 31→    if(typeof value === 'boolean') return value;
 32→    if(typeof value === 'string'){
 33→        const normalized = value.trim().toLowerCase();
 34→        if(normalized === 'true') return true;
 35→        if(normalized === 'false') return false;
 36→    }
 37→    if(typeof value === 'number'){
 38→        return value === 1;
 39→    }
 40→    return Boolean(value);
 41→};
 42→
 43→const normalizeCount = (value) => {
 44→    const number = Number(value);
 45→    if(!Number.isFinite(number) || number < 0){
 46→        return 0;
 47→    }
 48→    return number;
 49→};
 50→
 51→const getNextToggleCount = (isActive, currentCount) => {
 52→    return isActive
 53→        ? Math.max(0, currentCount - 1)
 54→        : currentCount + 1;
 55→};
